<?php
namespace Tests\Feature; use App\Enums\Crm\LeadPriority; use App\Enums\Crm\LeadStageType; use App\Enums\Crm\ProformaStatus; use App\Enums\Crm\QuotationStatus; use App\Enums\UserRole; use App\Models\Branch; use App\Models\Company; use App\Models\Crm\CrmLead; use App\Models\Crm\CrmLeadSource; use App\Models\Crm\CrmLeadStatus; use App\Models\Crm\CrmProformaInvoice; use App\Models\Crm\CrmQuotation; use App\Models\User; use Illuminate\Foundation\Testing\RefreshDatabase; use Tests\TestCase;
class CrmProformaInvoiceTest extends TestCase { use RefreshDatabase; public function test_quote_creation_payment_public_link_and_pdf_work():void{$u=$this->user(UserRole::Manager);$q=$this->quote($u);$payload=$this->payload();$this->actingAs($u)->post("/crm/proforma-invoices",$payload+['lead_id'=>$q->lead_id,'quotation_id'=>$q->id])->assertRedirect();$p=CrmProformaInvoice::firstOrFail();$this->assertSame('RPI-'.now()->format('Y').'-000001',$p->proforma_number);$this->assertSame('2360.00',$p->grand_total);$this->assertCount(1,$p->items);$this->actingAs($u)->post("/crm/proforma-invoices/$p->id/payments",['amount'=>1000,'payment_date'=>today()->toDateString(),'payment_mode'=>'upi'])->assertRedirect();$this->assertSame(ProformaStatus::PartiallyPaid,$p->refresh()->status);$this->actingAs($u)->post("/crm/proforma-invoices/$p->id/payments",['amount'=>1360,'payment_date'=>today()->toDateString(),'payment_mode'=>'upi'])->assertRedirect();$this->assertSame(ProformaStatus::Paid,$p->refresh()->status);$this->actingAs($u)->post("/crm/proforma-invoices/$p->id/public-link")->assertRedirect();$this->get('/pi/'.$p->refresh()->public_token)->assertOk()->assertDontSee('Internal secret');$this->actingAs($u)->get("/crm/proforma-invoices/$p->id/pdf")->assertOk()->assertHeader('content-type','application/pdf');} public function test_staff_cannot_create_and_overpayment_is_rejected():void{$m=$this->user(UserRole::Manager);$s=$this->user(UserRole::Staff,$m->company,$m->branch);$this->actingAs($s)->post('/crm/proforma-invoices',$this->payload())->assertForbidden();$p=CrmProformaInvoice::create(['company_id'=>$m->company_id,'proforma_number'=>'RPI-'.now()->format('Y').'-000001','title'=>'P','currency'=>'INR','invoice_date'=>today(),'grand_total'=>100,'balance_amount'=>100,'status'=>ProformaStatus::Sent,'created_by'=>$m->id]);$this->actingAs($m)->post("/crm/proforma-invoices/$p->id/payments",['amount'=>101,'payment_date'=>today()->toDateString(),'payment_mode'=>'cash'])->assertSessionHasErrors('amount');} private function payload():array{return ['title'=>'Proforma','customer_name'=>'Asha','customer_company'=>'Demo Retail','customer_email'=>'asha@example.test','customer_phone'=>'9000011111','currency'=>'INR','invoice_date'=>today()->toDateString(),'due_date'=>today()->addWeek()->toDateString(),'internal_remarks'=>'Internal secret','items'=>[['name'=>'Setup','quantity'=>1,'unit_price'=>2000,'discount_amount'=>0,'tax_rate'=>18]]];} private function quote(User $u):CrmQuotation{$source=CrmLeadSource::create(['company_id'=>$u->company_id,'name'=>'Web','slug'=>'web','is_active'=>true]);$status=CrmLeadStatus::create(['company_id'=>$u->company_id,'name'=>'Won','slug'=>'won','stage_type'=>LeadStageType::Won,'is_active'=>true]);$l=CrmLead::create(['company_id'=>$u->company_id,'branch_id'=>$u->branch_id,'source_id'=>$source->id,'status_id'=>$status->id,'assigned_user_id'=>$u->id,'created_by'=>$u->id,'title'=>'Lead','priority'=>LeadPriority::Medium]);return CrmQuotation::create(['company_id'=>$u->company_id,'lead_id'=>$l->id,'quotation_number'=>'RPQ-'.now()->format('Y').'-000001','title'=>'Quote','currency'=>'INR','status'=>QuotationStatus::Accepted,'created_by'=>$u->id]);} private function user(UserRole $r,?Company $c=null,?Branch $b=null):User{$c??=Company::factory()->create();$b??=Branch::factory()->for($c)->create();return User::factory()->for($c)->create(['branch_id'=>$b->id,'role'=>$r]);} }
